import React, { useCallback, useEffect, useState } from 'react';
import BreadCrumb from '../commoncomponent/breadcrumb/bread_crumb';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import { Modal, Select, Card, Input, Switch, Row, Col, Form, InputNumber } from 'antd';
import ConfigIcon from '../../images/config_icon.svg'
import '../../CSS/MasterData.css';
import { fetchMasterDataConf, getUserType, saveMasterDataConf } from '../APIConfig/MasterDataAction';
import { MASTER_DATA_SETTING, STATUS} from '../../utils/constants';
import { isEmpty } from 'lodash';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import { useStore } from '../hook-store/store';
import {getBasePath} from '../commoncomponent/BasePath';
import { Link } from 'react-router-dom';

const containerConstants = containerConstantsService.getInstance();
const { Option } = Select;
const { Item } = Form

const MasterData = (props) => {
    const store = useStore(true)[0];
    const [ basePath, setBasePath ]  = useState(''); 
    const [showModalDialogForm, setShowModalDialogForm] = useState(false);
    const [processing, setProcessing] = useState(false);
    const [validation, setValidation] = useState({});
    const [formData, setFormData] = useState({});
    const [allUserTypeList, setAllUserTypeList] = useState([]);


    const urlList =
        [
            {
                url: basePath+'/v2/label_generation/v2/settings',
                heading: containerConstants.formatString(containerConstants.SETTINGS),
            },
            {
                url: basePath+'/v2/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
            },
            {
                url: basePath+'/v2/label_generation/carrier_allocation',
                heading: containerConstants.formatString(containerConstants.CARRIER_ALLOCATION_AND_MASTER_VALIDATION)
            }
        ];

    const urlListForNewSetting =
    [
        {
            url: '/v2/new_settings/label_generation/settings',
            heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
        },
        {
            url: '/v2/new_settings/label_generation/carrier_allocation',
            heading: containerConstants.formatString(containerConstants.CARRIER_ALLOCATION_AND_MASTER_VALIDATION)
        }
    ];

    const masterDataTabClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/carrier_allocation/master_data'
                :
                basePath + '/v2/label_generation/carrier_allocation/master_data';
    };

    useEffect(() => {
        setBasePath(getBasePath(props, store));
        setValidation({});
        document.title = containerConstants.formatString(containerConstants.CARRIER_ALLOCATION_AND_MASTER_VALIDATION);
        fetchMasterDataConf()
            .then(response => {
                if (response && response.status === 200) {
                    setFormData(response.data);
                }
            })
            .catch(error => {

            });
        getUserType()
            .then(response => {
                if (response.status === 200) {
                    setAllUserTypeList(response.data)
                }
            })
            .catch(error => {

            });
    }, [showModalDialogForm]);

    const isEmptyData = () => {
        let emptyCount = 0
        Object.values(MASTER_DATA_SETTING).forEach(key => {
            if ((!formData[key] ||
                    (typeof formData[key] === 'string' ? isEmpty(formData[key].trim()) :
                    typeof formData[key] === 'number' ? formData[key] < 1 :
                    isEmpty(formData[key])))
                 && key !== MASTER_DATA_SETTING.IS_ENABLED ) {
                emptyCount++;
                setValidation(prev => ({ ...prev, [key]: 1 }));
            }
        })
        return !emptyCount ? false : true;
    }

    const switchClickHandler = (show) => {
        setFormData({ ...formData, [MASTER_DATA_SETTING.IS_ENABLED]: show });
        if (!isEmpty(formData) && formData.clientId) {
            saveMasterData(show)
        } else {
            setShowModalDialogForm(show);
        }
    }

    const saveMasterData = (show) => {
        const config = {};
        Object.values(MASTER_DATA_SETTING).forEach(key => {
            config[key] = typeof formData[key] === 'string' ? formData[key].trim():formData[key];
        })
        if (show !== undefined) {
            config[MASTER_DATA_SETTING.IS_ENABLED] = show;
            setProcessing(prev => !prev)
        }
        saveMasterDataConf(config)
            .then(response => {
                if ( response && response.status === 200) {
                    notifyResponseMessage(STATUS.SUCCESS, "Updated Successfully");
                    setFormData(response.data);
                    show !== undefined && setProcessing(prev => !prev);
                    props.updateCarrierAllocationName(response.data);
                }else{
                    if(formData.clientId === undefined){
                        setFormData({ ...formData, [MASTER_DATA_SETTING.IS_ENABLED]: show });
                    }
                    setProcessing(prev => !prev);
                    notifyResponseMessage(STATUS.ERROR, response.response.data);
                }

            })
            .catch(error => {
                if(formData.clientId === undefined){
                    setFormData({ ...formData, [MASTER_DATA_SETTING.IS_ENABLED]: show });
                }
                setProcessing(prev => !prev);
                notifyResponseMessage(STATUS.ERROR, error.message);
            });
    }

    const handleClickOk = () => {
        if (!isEmptyData()) {
            saveMasterData();
            setShowModalDialogForm(false)
        }
    }

    const handleClickCancel = () => {
        setValidation({})
        if(formData.clientId === undefined){
            setFormData({ ...formData, [MASTER_DATA_SETTING.IS_ENABLED]: false });
        }
        setShowModalDialogForm(false)
    }

    const updateFieldValue = (e, name) => {
        setFormData({ ...formData, [name]: e.target.value }); validation[name] && delete validation[name]
    }

    const getRowWithInputElementJsx = (label, name) => {
        return (
            <Row justify='space-between'>
                <Col span={6}>{label}</Col>
                <Col span={14}>
                    <Item
                        validateStatus={validation[name] ? 'error' : null}
                        help={validation[name] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, label) : null}
                    >
                        <Input name={name} value={formData[name]} onChange={(e) => updateFieldValue(e, name)} />
                    </Item>
                </Col>
            </Row>
        );
    }

    const getRowWithSelectElementJsx = (label, name) => {
        return (
            <Row justify='space-between'>
                <Col span={6}>{label}</Col>
                <Col span={14}>
                    <Item
                        validateStatus={validation[name] ? 'error' : null}
                        help={validation[name] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, label) : null}
                    >
                        <Select
                            mode='multiple'
                            allowClear
                            style={{ width: '100%' }}
                            showSearch
                            value={formData[name]}
                            onChange={value => {
                                setFormData({ ...formData, [name]: value });
                                validation[name] && delete validation[name]
                            }}
                            filterOption={(input, option) => option.props.children.toLowerCase().indexOf(input.toLowerCase()) >= 0}
                        >
                            {allUserTypeList.map(userType => (
                                <Option key={userType.id} value={userType.id + ""}>{userType.name}</Option>
                            ))}
                        </Select>
                    </Item>
                </Col>
            </Row>
        );
    }

    const handleAllocationOutputTypeChange =(value) =>{
          //
        if(value === "Single Carrier"){
            setFormData({ ...formData, noOfOutput:1, [MASTER_DATA_SETTING.ALLOCATION_OUTPUT]: value });
        }
        else{
            setFormData({ ...formData, [MASTER_DATA_SETTING.ALLOCATION_OUTPUT]: value });
        }
        validation[MASTER_DATA_SETTING.ALLOCATION_OUTPUT] && delete validation[MASTER_DATA_SETTING.ALLOCATION_OUTPUT]
    }

    const handleNoOfOutputChange = (value) => {
        setFormData({ ...formData, noOfOutput:value});
    }

    return (<div>
        <BreadCrumb urlList={store.fromNewSetting ? urlListForNewSetting :urlList} />
        <Modal
            title={containerConstants.formatString(containerConstants.SET_PREFERENCE)}
            visible={showModalDialogForm}
            centered
            maskClosable='true'
            className='master-data-modal'
            bodyStyle={{ padding: '16px 24px 0' }}
            width={'50%'}
            okText={containerConstants.formatString(containerConstants.ADD)}
            onOk={handleClickOk}
            onCancel={handleClickCancel}
        >
            <Card className='fw500 fs12 lh18' bodyStyle={{ color: '#727272', padding: '1rem 0 1.5rem' }} title={containerConstants.formatString(containerConstants.BASIC_DETAILS)}>
                {getRowWithInputElementJsx(containerConstants.formatString(containerConstants.TITLE), MASTER_DATA_SETTING.TITLE)}
                <br />
                {getRowWithSelectElementJsx(containerConstants.formatString(containerConstants.USER_TYPE), MASTER_DATA_SETTING.ALLOWED_USER_TYPES)}
                <br />
                <Row justify='space-between'>
                    <Col span={6}>{containerConstants.formatString(containerConstants.ALLOCATION_OUTPUT)} :</Col>
                    <Col span={14}>
                        <Item
                            validateStatus={validation[MASTER_DATA_SETTING.ALLOCATION_OUTPUT] ? 'error' : null}
                            help={validation[MASTER_DATA_SETTING.ALLOCATION_OUTPUT] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, containerConstants.formatString(containerConstants.ALLOCATION_OUTPUT)) : null}
                        >
                            <Select
                                style={{ width: '100%' }}
                                showSearch
                                value={formData[MASTER_DATA_SETTING.ALLOCATION_OUTPUT]}
                                onChange={value =>
                                    handleAllocationOutputTypeChange(value)
                                }
                                filterOption={(input, option) => option.props.children.toLowerCase().indexOf(input.toLowerCase()) >= 0}
                            >
                                <Option key = "Single_Carrier" value="Single Carrier">{containerConstants.formatString(containerConstants.SINGLE_CARRIER)}</Option>
                                <Option key = "Multi_Carrier" value="Multi Carrier">{containerConstants.formatString(containerConstants.MULTI_CARRIER)}</Option>
                            </Select>
                        </Item>
                    </Col>
                </Row>
                {formData.isEnabled && formData[MASTER_DATA_SETTING.ALLOCATION_OUTPUT] === "Multi Carrier" &&
                <>
                <br />
                    <Row justify='space-between'>
                    <Col span={6}>{containerConstants.formatString(containerConstants.NO_OF_OUTPUT)} :</Col>
                    <Col span={14}>

                        <Item
                            validateStatus={validation[MASTER_DATA_SETTING.NO_OF_OUTPUT] ? 'error' : null}
                            help={validation[MASTER_DATA_SETTING.NO_OF_OUTPUT] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, containerConstants.formatString(containerConstants.NO_OF_OUTPUT)) : null}
                        >
                            <InputNumber
                                style={{  height: '32px' }}
                                placeholder=""
                                name={MASTER_DATA_SETTING.NO_OF_OUTPUT}
                                value={formData[MASTER_DATA_SETTING.NO_OF_OUTPUT]}
                                onChange={(e) => handleNoOfOutputChange(e)}
                                />

                        </Item>
                    </Col>
                </Row>
                </>
                }
            </Card>
            <Card className='fw500 fs12 lh18' bodyStyle={{ color: '#727272', padding: '1rem 0 1.5rem' }} title={containerConstants.formatString(containerConstants.CARRIER_INTEGRATION)}>
                {getRowWithInputElementJsx(containerConstants.formatString(containerConstants.URL), MASTER_DATA_SETTING.URL)}
                <br />
                {getRowWithInputElementJsx(containerConstants.formatString(containerConstants.API_ACCESS_TOKEN), MASTER_DATA_SETTING.API_ACCESS_TOKEN)}
            </Card>
        </Modal>
        <Link to={masterDataTabClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
            <Card size='small' bodyStyle={{}} className='pointer' id='carrier-alloc-card' >
                <span>{containerConstants.formatString(containerConstants.MASTER_DATA)}</span>
            </Card>
        </Link>
        
        { ( store.fromFCR || ! store.showCustom ) && <Card size='small' bodyStyle={{}} id='carrier-alloc-card'>
            <div className='justify-space-btw'>
                <span>{containerConstants.formatString(containerConstants.SERVICE)}</span>
                <span id='switch-config-container'>
                    {formData[MASTER_DATA_SETTING.IS_ENABLED] && formData.clientId && <span style={{ paddingRight: '26px' }} >
                        <img className='pointer' src={ConfigIcon} onClick={() => setShowModalDialogForm(true)} /></span>}
                        <Switch loading={processing} disabled={processing} checked={formData[MASTER_DATA_SETTING.IS_ENABLED]} onClick={switchClickHandler}></Switch>
                </span>
            </div>
        </Card>}
    </div>);
};

export default MasterData;
